   103→Submission MakeSubmission(int id, User user, Problem problem, string code,
   104→    SubmissionStatus status, int score, int wallMs, int memKb, string stdout) =>
   105→    new Submission
   106→    {
   107→        Id = id, User = user, Problem = problem,
   108→        SourceCode = code, Language = "cpp",
   109→        Status = status, SubmittedAt = DateTime.Now.AddMinutes(-id * 3),
   110→        Score = score, WallTimeMs = wallMs, PeakMemoryKb = memKb,
   111→        ExecutionResult = new ExecutionResult
   112→        {
   113→            Id = id, Stdout = stdout, Stderr = "",
   114→            ExitCode = status == SubmissionStatus.CompileError ? 1 : 0,
   115→            TimedOut = status == SubmissionStatus.TimeLimitExceeded,
   116→            MemoryExceeded = status == SubmissionStatus.MemoryLimitExceeded
   117→        }
   118→    };
   119→
   120→var submissions = new List<Submission>
   121→{
   122→    MakeSubmission(1, user1, problem1, "// correct two sum",         SubmissionStatus.Accepted,           100, 45,   2048, "[0,1]"),
   123→    MakeSubmission(2, user1, problem2, "// sliding window solution", SubmissionStatus.Accepted,           100, 120,  4096, "3"),
   124→    MakeSubmission(3, user1, problem3, "// binary search attempt",   SubmissionStatus.WrongAnswer,         60, 200,  8192, "2.0"),
   125→    MakeSubmission(4, user2, problem1, "// brute force O(n^2)",      SubmissionStatus.Accepted,           100, 980,  2048, "[0,1]"),
   126→    MakeSubmission(5, user2, problem2, "// naive solution TLE",      SubmissionStatus.TimeLimitExceeded,    0, 2001, 4096, ""),
   127→    MakeSubmission(6, user2, problem3, "// correct binary search",   SubmissionStatus.Accepted,           100, 55,   4096, "2.5"),
   128→    MakeSubmission(7, user3, problem1, "// optimal hash map",        SubmissionStatus.Accepted,           100, 32,   1024, "[0,1]"),
   129→    MakeSubmission(8, user3, problem3, "// compile error",           SubmissionStatus.CompileError,         0, 0,      0, ""),
   130→};
   131→
   132→foreach (var s in submissions)
   133→{
   134→    s.User.Submissions.Add(s);
   135→    s.Problem.Submissions.Add(s);
   136→}
