   138→Console.WriteLine("=== WebIde Object Model - Lab 1 ===\n");
   139→Console.WriteLine($"Problems: {problems.Count} | Users: {users.Count} | Submissions: {submissions.Count}");
   140→Console.WriteLine($"Organization: {org.Name} | ProblemSet: {problemSet.Title}\n");
