   142→// ─── LINQ Queries ─────────────────────────────────────────────────────────────
   143→
   144→Console.WriteLine("─── 1. Easy problems ───────────────────────────────────────────");
   145→var easyProblems = problems
   146→    .Where(p => p.Difficulty == DifficultyLevel.Easy)
   147→    .ToList();
   148→foreach (var p in easyProblems)
   149→    Console.WriteLine($"  {p.Title} ({p.Difficulty})");
   150→
   151→Console.WriteLine("\n─── 2. Accepted submissions for ana_k (newest first) ────────────");
   152→var anaAccepted = user1.Submissions
   153→    .Where(s => s.Status == SubmissionStatus.Accepted)
   154→    .OrderByDescending(s => s.SubmittedAt)
   155→    .ToList();
   156→foreach (var s in anaAccepted)
   157→    Console.WriteLine($"  [{s.SubmittedAt:HH:mm:ss}] {s.Problem.Title} - score: {s.Score}");
   158→
   159→Console.WriteLine("\n─── 3. Problems tagged 'Arrays' ─────────────────────────────────");
   160→var arrayProblems = problems
   161→    .Where(p => p.Tags.Any(t => t.Name == "Arrays"))
   162→    .ToList();
   163→foreach (var p in arrayProblems)
   164→    Console.WriteLine($"  {p.Title}");
   165→
   166→Console.WriteLine("\n─── 4. Top 3 scorers on 'Two Sum' ──────────────────────────────");
   167→var topScorers = problem1.Submissions
   168→    .OrderByDescending(s => s.Score)
   169→    .ThenBy(s => s.WallTimeMs)
   170→    .Take(3)
   171→    .ToList();
   172→foreach (var s in topScorers)
   173→    Console.WriteLine($"  {s.User.DisplayName}: score={s.Score}, time={s.WallTimeMs}ms");
   174→
   175→Console.WriteLine("\n─── 5. Submission count per problem ─────────────────────────────");
   176→var submissionCounts = problems
   177→    .Select(p => new { p.Title, Count = p.Submissions.Count })
   178→    .OrderByDescending(x => x.Count)
   179→    .ToList();
   180→foreach (var x in submissionCounts)
   181→    Console.WriteLine($"  {x.Title}: {x.Count} submissions");
   182→
   183→Console.WriteLine("\n─── 6. Problems with no accepted submissions ────────────────────");
   184→var noAccepted = problems
   185→    .Where(p => !p.Submissions.Any(s => s.Status == SubmissionStatus.Accepted))
   186→    .ToList();
   187→if (noAccepted.Count == 0)
   188→    Console.WriteLine("  All problems have at least one accepted submission.");
   189→else
   190→    foreach (var p in noAccepted)
   191→        Console.WriteLine($"  {p.Title}");
   192→
   193→Console.WriteLine("\n─── 7. Sample test cases for 'Median of Two Sorted Arrays' ──────");
   194→var sampleCases = problem3.TestCases
   195→    .Where(tc => tc.IsSample)
   196→    .OrderBy(tc => tc.OrderIndex)
   197→    .ToList();
   198→foreach (var tc in sampleCases)
   199→    Console.WriteLine($"  Input: {tc.InputArgs} -> Expected: {tc.ExpectedOutput} ({tc.Points} pts)");
   200→
   201→// ─── Async Demo ───────────────────────────────────────────────────────────────
   202→
   203→Console.WriteLine("\n─── Async: simulate parallel code execution ─────────────────────");
   204→
   205→static async Task SimulateCodeExecutionAsync(Submission submission)
   206→{
   207→    int compileMs = new Random().Next(200, 600);
   208→    int runMs     = new Random().Next(100, 400);
   209→    Console.WriteLine($"  [{submission.User.Username}] Compiling '{submission.Problem.Title}'...");
   210→    await Task.Delay(compileMs);
   211→    Console.WriteLine($"  [{submission.User.Username}] Running '{submission.Problem.Title}'...");
   212→    await Task.Delay(runMs);
   213→    Console.WriteLine($"  [{submission.User.Username}] Done ~{compileMs + runMs}ms -> {submission.Status}");
   214→}
   215→
   216→var parallelSubmissions = new[] { submissions[0], submissions[3], submissions[6] };
   217→
   218→Console.WriteLine("  Launching 3 submissions in parallel via Task.WhenAll:");
   219→await Task.WhenAll(parallelSubmissions.Select(SimulateCodeExecutionAsync));
   220→
   221→Console.WriteLine("\nAll tasks completed.");
   222→

