   205→static async Task SimulateCodeExecutionAsync(Submission submission)
   206→{
   207→    int compileMs = new Random().Next(200, 600);
   208→    int runMs     = new Random().Next(100, 400);
   209→    Console.WriteLine($"  [{submission.User.Username}] Compiling '{submission.Problem.Title}'...");
   210→    await Task.Delay(compileMs);
   211→    Console.WriteLine($"  [{submission.User.Username}] Running '{submission.Problem.Title}'...");
   212→    await Task.Delay(runMs);
   213→    Console.WriteLine($"  [{submission.User.Username}] Done ~{compileMs + runMs}ms -> {submission.Status}");
   214→}
   215→
   216→var parallelSubmissions = new[] { submissions[0], submissions[3], submissions[6] };
   217→
   218→Console.WriteLine("  Launching 3 submissions in parallel via Task.WhenAll:");
   219→await Task.WhenAll(parallelSubmissions.Select(SimulateCodeExecutionAsync));
   220→
   221→Console.WriteLine("\nAll tasks completed.");
