## Step 7 — ProblemsController

**File:** `/Users/fbeleta/Documents/WebIde/Web_ide/WebIde.Api/Controllers/ProblemsController.cs`

```csharp
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using WebIde.Api.Data;
using WebIde.Api.DTOs;
using WebIde.Model;
using WebIde.Model.Enums;

namespace WebIde.Api.Controllers;

[ApiController]
[Route("api/[controller]")]
public class ProblemsController : ControllerBase
{
    private readonly AppDbContext _db;

    public ProblemsController(AppDbContext db)
    {
        _db = db;
    }

    // GET /api/problems?difficulty=Easy&tag=sorting
    [HttpGet]
    public async Task<ActionResult<IEnumerable<ProblemDto>>> GetAll(
        [FromQuery] string? difficulty,
        [FromQuery] string? tag,
        CancellationToken ct)
    {
        var query = _db.Problems
            .Include(p => p.Tags)
            .AsNoTracking()
            .AsQueryable();

        if (!string.IsNullOrWhiteSpace(difficulty))
        {
            if (!Enum.TryParse<DifficultyLevel>(difficulty, ignoreCase: true, out var level))
            {
                return ValidationProblem(
                    detail: $"Invalid difficulty '{difficulty}'. Valid values: Easy, Medium, Hard.",
                    title: "Invalid filter value");
            }
            query = query.Where(p => p.Difficulty == level);
        }

        if (!string.IsNullOrWhiteSpace(tag))
        {
            query = query.Where(p => p.Tags.Any(t => t.Name == tag));
        }

        var problems = await query
            .OrderBy(p => p.CreatedAt)
            .Select(p => MapToDto(p))
            .ToListAsync(ct);

        return Ok(problems);
    }

    // GET /api/problems/{id}
    [HttpGet("{id:int}")]
    public async Task<ActionResult<ProblemDto>> GetById(int id, CancellationToken ct)
    {
        var problem = await _db.Problems
            .Include(p => p.Tags)
            .AsNoTracking()
            .FirstOrDefaultAsync(p => p.Id == id, ct);

        if (problem is null)
            return NotFound(new ProblemDetails
            {
                Title = "Problem not found",
                Detail = $"No problem with id {id} exists.",
                Status = StatusCodes.Status404NotFound
            });

        return Ok(MapToDto(problem));
    }

    // POST /api/problems
    [HttpPost]
    public async Task<ActionResult<ProblemDto>> Create(
        [FromBody] CreateProblemRequest request,
        CancellationToken ct)
    {
        if (!Enum.TryParse<DifficultyLevel>(request.Difficulty, ignoreCase: true, out var difficulty))
        {
            return ValidationProblem(
                detail: $"Invalid difficulty '{request.Difficulty}'. Valid values: Easy, Medium, Hard.",
                title: "Invalid difficulty");
        }

        var problem = new Problem
        {
            Title = request.Title,
            Description = request.Description,
            Difficulty = difficulty,
            TimeLimitMs = request.TimeLimitMs,
            MemoryLimitKb = request.MemoryLimitKb,
            AuthorUsername = request.AuthorUsername,
            CreatedAt = DateTime.UtcNow
        };

        if (request.Tags is { Count: > 0 })
        {
            var tagNames = request.Tags.Distinct(StringComparer.OrdinalIgnoreCase).ToList();
            var existingTags = await _db.Tags
                .Where(t => tagNames.Contains(t.Name))
                .ToListAsync(ct);

            var existingNames = existingTags.Select(t => t.Name).ToHashSet(StringComparer.OrdinalIgnoreCase);
            var newTags = tagNames
                .Where(n => !existingNames.Contains(n))
                .Select(n => new Tag { Name = n });

            problem.Tags.AddRange(existingTags);
            problem.Tags.AddRange(newTags);
        }

        _db.Problems.Add(problem);
        await _db.SaveChangesAsync(ct);

        return CreatedAtAction(
            nameof(GetById),
            new { id = problem.Id },
            MapToDto(problem));
    }

    // PUT /api/problems/{id}
    [HttpPut("{id:int}")]
    public async Task<ActionResult<ProblemDto>> Update(
        int id,
        [FromBody] UpdateProblemRequest request,
        CancellationToken ct)
    {
        var problem = await _db.Problems
            .Include(p => p.Tags)
            .FirstOrDefaultAsync(p => p.Id == id, ct);

        if (problem is null)
            return NotFound(new ProblemDetails
            {
                Title = "Problem not found",
                Detail = $"No problem with id {id} exists.",
                Status = StatusCodes.Status404NotFound
            });

        if (!Enum.TryParse<DifficultyLevel>(request.Difficulty, ignoreCase: true, out var difficulty))
        {
            return ValidationProblem(
                detail: $"Invalid difficulty '{request.Difficulty}'.",
                title: "Invalid difficulty");
        }

        problem.Title = request.Title;
        problem.Description = request.Description;
        problem.Difficulty = difficulty;
        problem.TimeLimitMs = request.TimeLimitMs;
        problem.MemoryLimitKb = request.MemoryLimitKb;

        // Reconcile tags
        problem.Tags.Clear();
        if (request.Tags is { Count: > 0 })
        {
            var tagNames = request.Tags.Distinct(StringComparer.OrdinalIgnoreCase).ToList();
            var existingTags = await _db.Tags
                .Where(t => tagNames.Contains(t.Name))
                .ToListAsync(ct);

            var existingNames = existingTags.Select(t => t.Name).ToHashSet(StringComparer.OrdinalIgnoreCase);
            var newTags = tagNames
                .Where(n => !existingNames.Contains(n))
                .Select(n => new Tag { Name = n });

            problem.Tags.AddRange(existingTags);
            problem.Tags.AddRange(newTags);
        }

        await _db.SaveChangesAsync(ct);
        return Ok(MapToDto(problem));
    }

    // DELETE /api/problems/{id}
    [HttpDelete("{id:int}")]
    public async Task<IActionResult> Delete(int id, CancellationToken ct)
    {
        var problem = await _db.Problems.FindAsync([id], ct);

        if (problem is null)
            return NotFound(new ProblemDetails
            {
                Title = "Problem not found",
                Detail = $"No problem with id {id} exists.",
                Status = StatusCodes.Status404NotFound
            });

        _db.Problems.Remove(problem);
        await _db.SaveChangesAsync(ct);
        return NoContent();
    }

    private static ProblemDto MapToDto(Problem p) => new(
        p.Id,
        p.Title,
        p.Description,
        p.Difficulty.ToString(),
        p.TimeLimitMs,
        p.MemoryLimitKb,
        p.CreatedAt,
        p.AuthorUsername,
        p.Tags.Select(t => t.Name).ToList()
    );
}
```

Key implementation decisions:
- All 404 responses use `ProblemDetails` with `Title` and `Detail` fields, satisfying RFC 7807.
- `ValidationProblem()` also returns RFC 7807 format (it is built into ASP.NET Core via `ApiBehaviorOptions`).
- The `Select(p => MapToDto(p))` call in `GetAll` runs client-side after the EF query materializes. If you want server-side projection you would write a `.Select(p => new ProblemDto(...))` expression directly in the LINQ — but the `MapToDto` static helper keeps code DRY across actions.
- Tag upsert: on POST/PUT, existing tags are reused, new tags are created, avoiding unique constraint violations.
- `problem.Tags.Clear()` on PUT triggers EF Core to delete join table rows for the old tag associations. Tags themselves are not deleted (they may be shared with other problems).

