## Step 5 — AppDbContext (Full Fluent API Configuration)

**File:** `/Users/fbeleta/Documents/WebIde/Web_ide/WebIde.Api/Data/AppDbContext.cs`

```csharp
using Microsoft.EntityFrameworkCore;
using WebIde.Model;
using WebIde.Model.Enums;

namespace WebIde.Api.Data;

public class AppDbContext : DbContext
{
    public AppDbContext(DbContextOptions<AppDbContext> options) : base(options) { }

    public DbSet<User> Users => Set<User>();
    public DbSet<Organization> Organizations => Set<Organization>();
    public DbSet<Problem> Problems => Set<Problem>();
    public DbSet<ProblemSet> ProblemSets => Set<ProblemSet>();
    public DbSet<Submission> Submissions => Set<Submission>();
    public DbSet<TestCase> TestCases => Set<TestCase>();
    public DbSet<ExecutionResult> ExecutionResults => Set<ExecutionResult>();
    public DbSet<Tag> Tags => Set<Tag>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        base.OnModelCreating(modelBuilder);

        // ── User ────────────────────────────────────────────────────────────
        modelBuilder.Entity<User>(e =>
        {
            e.ToTable("users");
            e.HasKey(u => u.Id);
            e.Property(u => u.Id).UseIdentityAlwaysColumn();

            e.Property(u => u.Username)
                .IsRequired()
                .HasMaxLength(64);

            e.HasIndex(u => u.Username).IsUnique();

            e.Property(u => u.Email)
                .IsRequired()
                .HasMaxLength(256);

            e.HasIndex(u => u.Email).IsUnique();

            e.Property(u => u.DisplayName)
                .IsRequired()
                .HasMaxLength(128);

            e.Property(u => u.Role)
                .IsRequired()
                .HasConversion<string>()
                .HasMaxLength(32);

            e.Property(u => u.RegisteredAt)
                .IsRequired()
                .HasColumnType("timestamptz");

            // Navigation: Submissions configured on Submission side
            // Navigation: Organizations configured via join table below
        });

        // ── Organization ────────────────────────────────────────────────────
        modelBuilder.Entity<Organization>(e =>
        {
            e.ToTable("organizations");
            e.HasKey(o => o.Id);
            e.Property(o => o.Id).UseIdentityAlwaysColumn();

            e.Property(o => o.Name)
                .IsRequired()
                .HasMaxLength(256);

            e.Property(o => o.Description)
                .IsRequired();

            // N-N User ↔ Organization — explicit join table
            e.HasMany(o => o.Members)
                .WithMany(u => u.Organizations)
                .UsingEntity(
                    "organization_members",
                    l => l.HasOne(typeof(User))
                          .WithMany()
                          .HasForeignKey("user_id")
                          .OnDelete(DeleteBehavior.Cascade),
                    r => r.HasOne(typeof(Organization))
                          .WithMany()
                          .HasForeignKey("organization_id")
                          .OnDelete(DeleteBehavior.Cascade),
                    j =>
                    {
                        j.HasKey("organization_id", "user_id");
                        j.ToTable("organization_members");
                    });
        });

        // ── Tag ─────────────────────────────────────────────────────────────
        modelBuilder.Entity<Tag>(e =>
        {
            e.ToTable("tags");
            e.HasKey(t => t.Id);
            e.Property(t => t.Id).UseIdentityAlwaysColumn();

            e.Property(t => t.Name)
                .IsRequired()
                .HasMaxLength(64);

            e.HasIndex(t => t.Name).IsUnique();
        });

        // ── Problem ─────────────────────────────────────────────────────────
        modelBuilder.Entity<Problem>(e =>
        {
            e.ToTable("problems");
            e.HasKey(p => p.Id);
            e.Property(p => p.Id).UseIdentityAlwaysColumn();

            e.Property(p => p.Title)
                .IsRequired()
                .HasMaxLength(256);

            e.Property(p => p.Description)
                .IsRequired();

            e.Property(p => p.Difficulty)
                .IsRequired()
                .HasConversion<string>()
                .HasMaxLength(16);

            e.Property(p => p.TimeLimitMs)
                .IsRequired();

            e.Property(p => p.MemoryLimitKb)
                .IsRequired();

            e.Property(p => p.CreatedAt)
                .IsRequired()
                .HasColumnType("timestamptz");

            e.Property(p => p.AuthorUsername)
                .IsRequired()
                .HasMaxLength(64);

            // N-N Problem ↔ Tag — explicit join table
            e.HasMany(p => p.Tags)
                .WithMany(t => t.Problems)
                .UsingEntity(
                    "problem_tags",
                    l => l.HasOne(typeof(Tag))
                          .WithMany()
                          .HasForeignKey("tag_id")
                          .OnDelete(DeleteBehavior.Cascade),
                    r => r.HasOne(typeof(Problem))
                          .WithMany()
                          .HasForeignKey("problem_id")
                          .OnDelete(DeleteBehavior.Cascade),
                    j =>
                    {
                        j.HasKey("problem_id", "tag_id");
                        j.ToTable("problem_tags");
                    });

            // N-N Problem ↔ ProblemSet — explicit join table
            // Configured on ProblemSet side below to keep ProblemSet as the
            // "owning" side (ProblemSet.Problems is the primary navigation).
        });

        // ── ProblemSet ──────────────────────────────────────────────────────
        modelBuilder.Entity<ProblemSet>(e =>
        {
            e.ToTable("problem_sets");
            e.HasKey(ps => ps.Id);
            e.Property(ps => ps.Id).UseIdentityAlwaysColumn();

            e.Property(ps => ps.Title)
                .IsRequired()
                .HasMaxLength(256);

            e.Property(ps => ps.Description)
                .IsRequired();

            e.Property(ps => ps.CreatedAt)
                .IsRequired()
                .HasColumnType("timestamptz");

            e.Property(ps => ps.IsPublic)
                .IsRequired();

            e.Property(ps => ps.OrderIndex)
                .IsRequired();

            // 1-N Organization → ProblemSets
            e.HasOne(ps => ps.Organization)
                .WithMany(o => o.ProblemSets)
                .HasForeignKey("organization_id")
                .IsRequired()
                .OnDelete(DeleteBehavior.Cascade);

            // N-N Problem ↔ ProblemSet — explicit join table
            e.HasMany(ps => ps.Problems)
                .WithMany(p => p.ProblemSets)  // Note: ProblemSets nav must exist — see note below
                .UsingEntity(
                    "problem_set_problems",
                    l => l.HasOne(typeof(Problem))
                          .WithMany()
                          .HasForeignKey("problem_id")
                          .OnDelete(DeleteBehavior.Cascade),
                    r => r.HasOne(typeof(ProblemSet))
                          .WithMany()
                          .HasForeignKey("problem_set_id")
                          .OnDelete(DeleteBehavior.Cascade),
                    j =>
                    {
                        j.HasKey("problem_set_id", "problem_id");
                        j.Property<int>("order_index").HasDefaultValue(0);
                        j.ToTable("problem_set_problems");
                    });
        });

        // ── TestCase ─────────────────────────────────────────────────────────
        modelBuilder.Entity<TestCase>(e =>
        {
            e.ToTable("test_cases");
            e.HasKey(tc => tc.Id);
            e.Property(tc => tc.Id).UseIdentityAlwaysColumn();

            e.Property(tc => tc.InputArgs).IsRequired();
            e.Property(tc => tc.ExpectedOutput).IsRequired();
            e.Property(tc => tc.IsSample).IsRequired();
            e.Property(tc => tc.OrderIndex).IsRequired();
            e.Property(tc => tc.Points).IsRequired();

            // 1-N Problem → TestCases
            e.HasOne(tc => tc.Problem)
                .WithMany(p => p.TestCases)
                .HasForeignKey("problem_id")
                .IsRequired()
                .OnDelete(DeleteBehavior.Cascade);
        });

        // ── ExecutionResult ──────────────────────────────────────────────────
        modelBuilder.Entity<ExecutionResult>(e =>
        {
            e.ToTable("execution_results");
            e.HasKey(er => er.Id);
            e.Property(er => er.Id).UseIdentityAlwaysColumn();

            e.Property(er => er.Stdout).IsRequired();
            e.Property(er => er.Stderr).IsRequired();
            e.Property(er => er.ExitCode).IsRequired();
            e.Property(er => er.TimedOut).IsRequired();
            e.Property(er => er.MemoryExceeded).IsRequired();
        });

        // ── Submission ───────────────────────────────────────────────────────
        modelBuilder.Entity<Submission>(e =>
        {
            e.ToTable("submissions");
            e.HasKey(s => s.Id);
            e.Property(s => s.Id).UseIdentityAlwaysColumn();

            e.Property(s => s.SourceCode).IsRequired();

            e.Property(s => s.Language)
                .IsRequired()
                .HasMaxLength(32);

            e.Property(s => s.Status)
                .IsRequired()
                .HasConversion<string>()
                .HasMaxLength(32);

            e.Property(s => s.SubmittedAt)
                .IsRequired()
                .HasColumnType("timestamptz");

            e.Property(s => s.Score).IsRequired();
            e.Property(s => s.WallTimeMs).IsRequired();
            e.Property(s => s.PeakMemoryKb).IsRequired();

            // 1-N User → Submissions
            e.HasOne(s => s.User)
                .WithMany(u => u.Submissions)
                .HasForeignKey("user_id")
                .IsRequired()
                .OnDelete(DeleteBehavior.Restrict);  // Prevent cascade delete wiping submissions

            // 1-N Problem → Submissions
            e.HasOne(s => s.Problem)
                .WithMany(p => p.Submissions)
                .HasForeignKey("problem_id")
                .IsRequired()
                .OnDelete(DeleteBehavior.Restrict);

            // 0-1 Submission → ExecutionResult
            e.HasOne(s => s.ExecutionResult)
                .WithOne()
                .HasForeignKey<Submission>("execution_result_id")
                .IsRequired(false)
                .OnDelete(DeleteBehavior.SetNull);
        });
    }
}
```

**Important design note on `Problem.ProblemSets`:** The `Problem` domain model does not currently have a `ProblemSets` navigation property (it is not listed in the task's key properties). The N-N configuration `.WithMany(p => p.ProblemSets)` requires that navigation to exist. You have two options:

- **Option A (recommended):** Add `public List<ProblemSet> ProblemSets { get; set; }` to `Problem.cs`. This is a pure model addition with zero EF Core coupling — it is just a C# collection property.
- **Option B:** Use `.WithMany()` (no argument, no navigation property on `Problem` side). EF Core supports this when the inverse navigation is not needed. Change to `.WithMany()` and skip adding the property if you want to avoid touching `Problem.cs`.

Given the requirement to keep the model pure, Option B is the safer choice if touching `Problem.cs` is undesirable, but Option A is cleaner for a complete domain model.

